/* eslint-disable no-undef */
import { devWarning, warning } from '../util';
import type { CompleteLocale } from './locales';
import enUS from './locales/en-US';

/**
 * 提供需要加载的 localeName，异步返回 localeData
 */
export const importLocale = async (locale: CompleteLocale['locale']) => {
  // storybook 直接加载源码所以是 ts 结尾，但是 build 以后的产物都是 js 不写 js 后缀的话 rollup 会提示处理不了，webpack5 会加载 d.ts 之类的文件，所以需要加上 .js
  let promise: Promise<any>;
  if (process.env.__BUILD__ === 'babel') {
    promise = import(`./locales/${locale}.js`);
  } else if (process.env.__BUILD__ === 'rollup') {
    promise = import(`./locales/${locale}.ts`);
  } else {
    promise = import(`./locales/${locale}`);
  }
  return promise
    .then(({ default: localeData }) => localeData as CompleteLocale)
    .catch((err: Error) => {
      warning(
        false,
        devWarning(
          'importLocale',
          // eslint-disable-next-line max-len
          `${err.message}. Locale name \`${locale}\` is not valid or something unexpected occurs. Your app will use \`en-US\` as a fallback.`,
        ),
      );
      return enUS;
    });
};
